729     // 2) Base == nullptr, Offset != 0 -> poison as the result is out of bounds
730     // 3) Base != nullptr, Offset == (-base) -> poison (crossing allocations)
731     // 4) Base != nullptr, Offset != (-base) -> nonnull (and possibly poison)
732     //
